  return (
    <div className="relative flex h-screen bg-white overflow-hidden font-sans text-gray-900">
      <div className="w-full h-full flex flex-col">
        <AIChat onLogout={handleLogout} />
      </div>
      <TicketManager />
    </div>
  );
