                <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 mt-1 shadow-sm ${msg.role === 'user' ? 'bg-[#1e293b] text-white' : 'bg-white border border-blue-100 text-blue-500'}`}>
