                                                <p className="font-mono text-[10px] leading-relaxed whitespace-pre-line">{ticket.troubleshootingLog}</p>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    </div>
  );
};

